{
  "executive_summary": "Design a unified API Gateway architecture that consolidates authentication, rate limiting, and traffic isolation into a single ingress layer, replacing the current inconsistent per-service implementations. The gateway uses a tiered routing model with three distinct entry points (mobile, partner, internal) that converge on shared downstream services through a common gateway core, enforcing consistent security policies while preserving consumer-specific behavior.",

  "architecture": {
    "components": [
      {
        "name": "API Gateway Core",
        "responsibility": "Single ingress point for all external traffic. Performs TLS termination, request routing, request/response transformation, correlation ID injection, and access logging. Does NOT contain business logic.",
        "boundaries": "Owns the edge — everything between the internet and the internal service mesh. No direct database access. Stateless; all state lives in Redis or the Auth Provider."
      },
      {
        "name": "Auth Module",
        "responsibility": "Pluggable authentication module within the gateway. Supports two strategies: JWT/OAuth2 for mobile consumers, API Key (via header X-API-Key) for partner consumers. Attaches a normalized identity context (principal ID, consumer type, scopes) to every authenticated request.",
        "boundaries": "Reads from Auth Provider and API Key Registry. Never issues tokens — that is the Auth Provider's job. Internal traffic bypasses this module entirely."
      },
      {
        "name": "Rate Limiter Module",
        "responsibility": "Enforces per-consumer-type rate limits using a sliding window algorithm backed by Redis. Mobile: 100 req/min keyed by user ID. Partner: 1,000 req/min keyed by partner API key. Internal: no limit. Returns standard 429 responses with Retry-After headers.",
        "boundaries": "Stateless in-process; all counters live in Redis. Does not make downstream calls. Executes after auth (needs the resolved identity to key the counter)."
      },
      {
        "name": "Router / Traffic Classifier",
        "responsibility": "Classifies inbound requests into one of three tiers (mobile, partner, internal) based on the listener/port and path prefix. Routes to the correct upstream service. Applies tier-specific middleware chains.",
        "boundaries": "Configuration-driven (declarative route table). No business logic. Changes to routing require config deployment, not code changes."
      },
      {
        "name": "Webhook Dispatch Service",
        "responsibility": "Asynchronous delivery of webhook events to partner-registered endpoints. Implements exponential backoff retry (max 5 attempts), payload signing (HMAC-SHA256), delivery logging, and a dead-letter queue for persistent failures.",
        "boundaries": "Separate process from the gateway — not in the hot path. Consumes domain events from an internal message broker. Owns the webhook subscription registry."
      },
      {
        "name": "Internal Service Mesh / Network Boundary",
        "responsibility": "Network-level isolation ensuring internal services are unreachable from external traffic. Internal-to-internal calls use a separate listener (port or network interface) with no auth overhead but with mTLS for transport security.",
        "boundaries": "Enforced at infrastructure level (network policies, security groups). The gateway does NOT proxy internal-to-internal traffic — those calls go direct within the mesh."
      },
      {
        "name": "Auth Provider (External/Existing)",
        "responsibility": "Issues and validates JWTs for mobile users. Existing system (e.g., Auth0, Keycloak, or custom). The gateway validates tokens against this provider's JWKS endpoint.",
        "boundaries": "Not owned by this design. Gateway is a consumer of its JWKS/introspection API."
      },
      {
        "name": "Redis (Rate Limit + Cache Store)",
        "responsibility": "Stores sliding window counters for rate limiting. Optionally caches JWKS keys and API key lookups to reduce latency on the auth hot path.",
        "boundaries": "Shared infrastructure. Must be deployed in-region with the gateway for sub-millisecond latency. No business data stored here."
      }
    ],
    "interfaces": [
      {
        "from": "Mobile App",
        "to": "API Gateway Core",
        "contract": "HTTPS on port 443, path prefix /api/v1/*, Authorization: Bearer <JWT>. Gateway validates JWT signature and expiry, extracts user_id claim.",
        "coupling_type": "loose — mobile app only knows the gateway's public URL and the token format"
      },
      {
        "from": "Partner Systems",
        "to": "API Gateway Core",
        "contract": "HTTPS on port 443, path prefix /partner/v1/*, X-API-Key header. Gateway resolves API key to partner identity, checks scopes.",
        "coupling_type": "loose — partners know only their API key and the endpoint contract"
      },
      {
        "from": "Internal Services",
        "to": "Internal Listener",
        "contract": "mTLS on internal port (e.g., 8443), path prefix /internal/*. No auth token required. Caller identity established via client certificate CN.",
        "coupling_type": "platform — coupled to internal network topology but decoupled from business logic"
      },
      {
        "from": "API Gateway Core",
        "to": "Auth Module",
        "contract": "In-process middleware call. Receives raw request, returns enriched request with identity context or 401/403 rejection.",
        "coupling_type": "tight (intentional) — auth is a core gateway concern"
      },
      {
        "from": "API Gateway Core",
        "to": "Rate Limiter Module",
        "contract": "In-process middleware call after auth. Uses identity context to select rate limit tier and key. Returns pass-through or 429.",
        "coupling_type": "tight (intentional) — rate limiting is a core gateway concern"
      },
      {
        "from": "Rate Limiter Module",
        "to": "Redis",
        "contract": "INCR + EXPIRE on sliding window key pattern: ratelimit:{tier}:{identity}:{window}. Lua script for atomicity.",
        "coupling_type": "infrastructure — replaceable with any atomic counter store"
      },
      {
        "from": "Downstream Services",
        "to": "Webhook Dispatch Service",
        "contract": "Publishes domain events to message broker (e.g., topic: logistics.events). Webhook service subscribes and filters by partner subscriptions.",
        "coupling_type": "loose — async, event-driven, no direct coupling"
      },
      {
        "from": "Webhook Dispatch Service",
        "to": "Partner Endpoints",
        "contract": "POST to partner-registered URL with JSON payload, X-Webhook-Signature header (HMAC-SHA256 of body with partner secret). Expects 2xx within 10s.",
        "coupling_type": "loose — fire-and-forget with retry"
      }
    ],
    "data_flow": "External request → TLS termination → Traffic Classifier (determines tier by listener/path) → Auth Module (JWT validation for mobile, API key lookup for partner, skip for internal) → Rate Limiter (applies tier-appropriate limit) → Route to upstream service with enriched headers (X-Consumer-Id, X-Consumer-Type, X-Request-Id) → Service processes and responds → Gateway returns response with standard headers (X-RateLimit-Remaining, X-RateLimit-Reset). For webhooks: service emits domain event → message broker → Webhook Dispatch Service → partner endpoint with signed payload and retries.",
    "patterns_used": [
      {
        "pattern": "API Gateway / Edge Server",
        "rationale": "Centralizes cross-cutting concerns (auth, rate limiting, logging, routing) that are currently scattered inconsistently across services. Single point of policy enforcement eliminates the class of bugs where one service has weaker auth than another."
      },
      {
        "pattern": "Middleware Pipeline (Chain of Responsibility)",
        "rationale": "Auth → Rate Limit → Route as composable middleware steps. Each concern is isolated, testable independently, and the order is explicit. New concerns (e.g., request validation, IP allowlisting) slot in without modifying existing middleware."
      },
      {
        "pattern": "Sliding Window Rate Limiting",
        "rationale": "More accurate than fixed-window (avoids burst-at-boundary problem) while being simple to implement with Redis INCR + TTL. Provides predictable behavior for consumers."
      },
      {
        "pattern": "Async Webhook Delivery with Dead Letter Queue",
        "rationale": "Decouples webhook delivery from the request hot path. Partners get reliable delivery with retry semantics. Dead-letter queue ensures no events are silently lost, and operations can investigate and replay failures."
      },
      {
        "pattern": "Network-Level Isolation (Defense in Depth)",
        "rationale": "Internal services are isolated not just by 'skipping auth' but by being unreachable from external networks entirely. This is the only reliable way to enforce the 'no auth needed for internal' requirement without risking accidental exposure."
      },
      {
        "pattern": "Strangler Fig (Migration Strategy)",
        "rationale": "Existing services keep their auth logic initially. Gateway is deployed alongside and traffic is migrated route-by-route. Once all traffic flows through the gateway, per-service auth is removed. Zero big-bang risk."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Gateway / Edge",
        "classification": "generic",
        "aggregates": ["RouteConfiguration", "ConsumerIdentity"]
      },
      {
        "name": "Access Control",
        "classification": "supporting",
        "aggregates": ["APIKey", "PartnerRegistration", "RateLimitPolicy"]
      },
      {
        "name": "Webhook Delivery",
        "classification": "supporting",
        "aggregates": ["WebhookSubscription", "DeliveryAttempt"]
      },
      {
        "name": "Logistics Core",
        "classification": "core",
        "aggregates": ["(existing domain aggregates — not in scope of this design)"]
      }
    ],
    "context_map": [
      {
        "upstream": "Access Control",
        "downstream": "Gateway / Edge",
        "relationship": "Open Host Service — Access Control exposes a published API (JWKS endpoint, API key validation) that the Gateway consumes. Gateway conforms to the auth provider's token format."
      },
      {
        "upstream": "Logistics Core",
        "downstream": "Webhook Delivery",
        "relationship": "Customer-Supplier — Core domain publishes domain events. Webhook Delivery subscribes and transforms events into partner-facing webhook payloads. Webhook Delivery has no influence on event schema."
      },
      {
        "upstream": "Gateway / Edge",
        "downstream": "Logistics Core",
        "relationship": "Anti-Corruption Layer — Gateway translates external consumer identity into a normalized header contract (X-Consumer-Id, X-Consumer-Type). Core services never parse JWTs or API keys directly."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Single gateway instance vs. separate gateways per consumer type",
      "gains": "Single gateway: unified logging, single deployment artifact, shared route configuration, lower operational overhead. One place to update TLS certs, one place to monitor.",
      "sacrifices": "Blast radius — a misconfiguration or resource exhaustion affects all consumer types. Slightly more complex routing configuration.",
      "alternatives_considered": [
        "Separate gateway per tier (mobile-gw, partner-gw, internal-gw): better isolation but 3x operational overhead and configuration drift risk",
        "Service mesh sidecar (Envoy/Istio): powerful but high complexity for a team that currently has no gateway at all — over-engineering"
      ]
    },
    {
      "decision": "Redis-backed sliding window vs. in-memory rate limiting",
      "gains": "Works across multiple gateway instances (horizontal scaling). Survives gateway restarts. Single source of truth for rate state.",
      "sacrifices": "Adds Redis as a hard dependency on the request hot path. ~1ms latency per rate limit check. If Redis goes down, must decide: fail-open (no rate limiting) or fail-closed (reject all).",
      "alternatives_considered": [
        "In-memory (local counters): no external dependency but breaks with multiple gateway instances and resets on restart",
        "Token bucket with Redis: slightly more complex implementation for similar results"
      ]
    },
    {
      "decision": "Webhook delivery as a separate service vs. gateway plugin",
      "gains": "Separate service: independent scaling, failure isolation (webhook retries don't affect gateway throughput), clearer ownership boundary.",
      "sacrifices": "Additional service to deploy and monitor. Requires a message broker.",
      "alternatives_considered": [
        "Gateway-embedded webhook dispatch: simpler deployment but couples webhook retry logic to the request-serving process",
        "Third-party webhook service (e.g., Svix): less control but zero build cost — worth evaluating if team is small"
      ]
    },
    {
      "decision": "Strangler fig migration vs. big-bang cutover",
      "gains": "Incremental migration: each route can be tested independently, easy rollback per route, no flag day.",
      "sacrifices": "Temporary dual-path complexity — some routes go through gateway, some go direct. Must maintain per-service auth until full migration.",
      "alternatives_considered": [
        "Big-bang cutover: simpler end state faster, but a single deployment with high blast radius on a system that currently has no gateway experience"
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "Auth strategy per consumer type",
      "evolution_path": "Auth module is pluggable by consumer tier. Adding a new auth mechanism (e.g., mTLS for a new partner tier, or SAML for enterprise customers) requires adding a new auth strategy implementation without modifying existing ones. The normalized identity context (principal ID, type, scopes) is the stable interface."
    },
    {
      "area": "Rate limit policies",
      "evolution_path": "Rate limits are configuration-driven per tier, not hardcoded. Can evolve to per-endpoint limits, burst allowances, or dynamic limits based on partner SLA tier without code changes — only config updates."
    },
    {
      "area": "Webhook event types",
      "evolution_path": "Webhook subscriptions are per-event-type. As the logistics domain adds new event types, the webhook service picks them up automatically from the broker. Partners subscribe to the events they care about."
    },
    {
      "area": "Gateway technology",
      "evolution_path": "The design is technology-agnostic. Can be implemented with Kong, AWS API Gateway + Lambda authorizers, Envoy, NGINX with Lua, or a custom Node/Go service. The middleware pipeline pattern maps to all of these."
    }
  ],

  "rigidity_points": [
    {
      "area": "Normalized identity header contract (X-Consumer-Id, X-Consumer-Type, X-Request-Id)",
      "reason": "This is the stable interface between the gateway and all downstream services. Changing this contract requires updating every service consumer. Make it right from day one and version it if it must change. This rigidity is intentional — it's the anti-corruption layer boundary."
    },
    {
      "area": "Network isolation of internal listener",
      "reason": "Internal services must be unreachable from external networks at the infrastructure level. This is a security invariant, not a configuration option. Relaxing it for convenience would undermine the entire security model."
    },
    {
      "area": "Rate limit fail-open vs. fail-closed policy",
      "reason": "Must be decided upfront and enforced consistently. If Redis is unreachable, the gateway either allows all traffic (fail-open, risk of abuse) or rejects all traffic (fail-closed, risk of outage). This is a policy decision, not a per-request decision. Recommend: fail-open with alerting for a logistics platform where availability matters more than abuse prevention."
    }
  ],

  "risks": [
    {
      "risk": "Single point of failure — all external traffic flows through one gateway",
      "severity": "critical",
      "mitigation": "Deploy gateway as a horizontally scaled, stateless cluster behind a load balancer. Health checks on /healthz. Auto-scaling based on request rate. At least 2 instances in different availability zones. Circuit breaker on downstream services so one bad upstream doesn't take down the gateway."
    },
    {
      "risk": "Redis failure causes rate limiting to stop or causes total request failure",
      "severity": "high",
      "mitigation": "Fail-open policy: if Redis is unreachable, skip rate limiting and emit a high-severity alert. Redis deployed as a cluster with replication. Rate limiter uses a short timeout (50ms) — if Redis doesn't respond, proceed without limiting."
    },
    {
      "risk": "Migration period with dual auth paths creates security gaps",
      "severity": "high",
      "mitigation": "During strangler fig migration, maintain a checklist of which routes are gateway-managed vs. service-managed. Run both in parallel for a burn-in period per route. Automated integration tests that verify auth is enforced for every public route regardless of path."
    },
    {
      "risk": "Webhook delivery falls behind under high event volume",
      "severity": "medium",
      "mitigation": "Webhook service scales independently. Dead-letter queue captures failures. Monitoring on queue depth and delivery latency. Circuit breaker per partner endpoint — if a partner is consistently down, stop retrying and alert."
    },
    {
      "risk": "API key leakage for partner integrations",
      "severity": "high",
      "mitigation": "API keys are hashed at rest (bcrypt or SHA-256 with salt). Key rotation API allows partners to rotate without downtime (support two active keys during rotation). Keys are never logged — gateway logs only the partner ID resolved from the key."
    },
    {
      "risk": "Inconsistent auth removal from downstream services during migration",
      "severity": "medium",
      "mitigation": "After gateway migration is complete for a route, downstream services should reject requests that lack the X-Consumer-Id header (proving they came through the gateway). This acts as a safety net — if someone bypasses the gateway, the request fails rather than succeeding without auth."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Phase 1 (Week 1-2): Deploy gateway infrastructure with TLS termination, request logging, and correlation ID injection. No auth or rate limiting yet — pure pass-through proxy. Route one low-risk mobile endpoint through it. Phase 2 (Week 3-4): Add Auth Module with JWT validation for mobile tier. Migrate mobile routes incrementally. Add Rate Limiter Module with Redis backing for mobile tier (100 req/min). Phase 3 (Week 5-6): Add API key auth for partner tier. Migrate partner routes. Apply partner rate limits (1,000 req/min). Phase 4 (Week 7-8): Set up internal listener on separate port/network interface. Configure network policies to isolate it from external traffic. Migrate internal routes. Phase 5 (Week 9-10): Deploy Webhook Dispatch Service. Integrate with message broker. Onboard first partner webhook subscription. Phase 6 (Ongoing): Remove per-service auth implementations as each route is confirmed stable through the gateway. Add downstream header validation (reject requests missing X-Consumer-Id).",
    "files_to_create_or_modify": [
      "gateway/src/server.ts — Gateway core: TLS termination, middleware pipeline orchestration, health check endpoint",
      "gateway/src/middleware/auth.ts — Auth middleware: JWT validation strategy, API key validation strategy, identity context enrichment",
      "gateway/src/middleware/rate-limiter.ts — Rate limiter middleware: sliding window algorithm, Redis client, tier-based configuration",
      "gateway/src/middleware/request-context.ts — Injects X-Request-Id (correlation), X-Consumer-Id, X-Consumer-Type headers",
      "gateway/src/routes/config.ts — Declarative route table: path patterns → upstream services, per-route middleware chain",
      "gateway/src/routes/mobile.routes.ts — Mobile tier route definitions with auth + rate limit middleware",
      "gateway/src/routes/partner.routes.ts — Partner tier route definitions with API key auth + rate limit + scope checks",
      "gateway/src/routes/internal.routes.ts — Internal tier route definitions, separate listener, no auth middleware",
      "gateway/src/config/rate-limits.ts — Rate limit tier configuration: { mobile: { window: 60s, max: 100 }, partner: { window: 60s, max: 1000 } }",
      "webhook-service/src/server.ts — Webhook Dispatch Service: event consumer, delivery engine, retry scheduler",
      "webhook-service/src/delivery.ts — HMAC-SHA256 payload signing, HTTP delivery with timeout, exponential backoff",
      "webhook-service/src/subscriptions.ts — Partner webhook subscription registry (CRUD + event type filtering)",
      "infra/network-policies.yaml — Kubernetes NetworkPolicy (or equivalent) isolating internal listener from external ingress",
      "gateway/tests/ — Integration tests: auth enforcement per tier, rate limit behavior, header enrichment, 401/403/429 responses"
    ],
    "patterns_to_follow": "Middleware pipeline pattern for composable request processing. Strategy pattern for auth (JWT vs API key). Configuration-driven routing (no business logic in the gateway). Async event-driven webhook delivery. Infrastructure-level network isolation for internal traffic. Fail-open with alerting for rate limiter Redis dependency. Strangler fig for incremental migration.",
    "pitfalls_to_avoid": [
      "DO NOT put business logic in the gateway — it routes, authenticates, rate limits, and logs. Nothing else.",
      "DO NOT use a single shared rate limit counter across consumer types — key by (tier, identity) to prevent one partner from consuming another's quota.",
      "DO NOT rely solely on the gateway for internal service isolation — enforce at the network layer. A misconfigured gateway route should not expose internal services.",
      "DO NOT log API keys, JWTs, or other credentials — log only the resolved identity (partner ID, user ID).",
      "DO NOT hardcode rate limits — make them configurable per tier and ideally per individual consumer for future flexibility.",
      "DO NOT skip the migration burn-in period — run gateway auth and service auth in parallel for each route before removing service-level auth.",
      "DO NOT make webhook delivery synchronous or in the gateway hot path — it must be async via a message broker.",
      "DO NOT implement your own JWT validation library — use a battle-tested library that handles JWKS rotation, clock skew, and algorithm verification."
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 85,
    "high_confidence_areas": [
      "API Gateway as the correct pattern for consolidating inconsistent auth — this is a textbook use case",
      "Middleware pipeline architecture for composable cross-cutting concerns",
      "Redis-backed sliding window for distributed rate limiting",
      "Network-level isolation for internal services (defense in depth)",
      "Strangler fig migration strategy to avoid big-bang risk",
      "Async webhook delivery as a separate service"
    ],
    "low_confidence_areas": [
      "Specific technology choice (Kong vs custom vs cloud-native) — depends on team expertise and existing infrastructure, which is unknown",
      "Exact rate limit numbers (100/1000 per min) — may need tuning based on actual traffic patterns; the architecture supports changing these trivially",
      "Message broker choice for webhook events — depends on existing infrastructure (Kafka, RabbitMQ, SQS, etc.)"
    ],
    "assumptions": [
      "The team has or can provision Redis infrastructure for rate limiting",
      "A message broker exists or can be introduced for webhook event delivery",
      "The platform runs on infrastructure that supports network-level isolation (Kubernetes, VPC, etc.)",
      "An identity provider (Auth0, Keycloak, custom) already exists for issuing mobile user JWTs",
      "The team has sufficient operational capacity to own a gateway deployment",
      "Current service count is manageable with a single gateway cluster (not hundreds of services requiring a service mesh)"
    ]
  }
}

